1	/**
2	 * WP Engine CAPI resolvers.
3	 *
4	 * Covers: nexusWpeStatus, nexusWpeLogin, nexusWpeLogout, nexusWpeAccounts,
5	 * nexusWpeInstalls, nexusWpeInstall, nexusWpeBackup, nexusWpeFleetHealth,
6	 * and all other nexusWpe* resolvers.
7	 */
8	
9	import type { NexusServices } from '../../types/nexus-services';
10	import type { ResolverParent } from '../resolver-utils';
11	import {
12	  buildDateRange,
13	  getUsageCached,
14	  isCurrentMonthRange,
15	  makeUsageCacheKey,
16	  setUsageCached,
17	} from '../../mcp/modules/wpe/usage-cache';
18	
19	const REQUIRES_WPE_AUTH = 'Not authenticated with WP Engine. Use wpe_login or authenticate in Local.';
20	
21	export function createWpeResolvers(services: NexusServices) {
22	  return {
23	    nexusWpeStatus: async () => {
24	      try {
25	        if (!services.localServices) return { success: true, authenticated: false };
26	        const userInfo = await services.localServices.wpeGetUserInfo();
27	        if (!userInfo) return { success: true, authenticated: false };
28	        return { success: true, authenticated: true, email: userInfo.email ?? null, accountName: userInfo.accountName ?? null };
29	      } catch (err: any) {
30	        return { success: false, error: err.message, authenticated: false };
31	      }
32	    },
33	
34	    nexusWpeLogin: async () => {
35	      try {
36	        if (!services.localServices) return { success: false, error: 'Local services not available' };
37	        services.localServices.wpeAuthenticate().catch(() => {});
38	        return { success: true, email: null };
39	      } catch (err: any) {
40	        return { success: false, error: err.message };
41	      }
42	    },
43	
44	    nexusWpeLogout: async () => {
45	      try {
46	        if (!services.localServices) return { success: false, error: 'Local services not available' };
47	        await services.localServices.wpeLogout();
48	        return { success: true };
49	      } catch (err: any) {
